import{_ as t,o as a,c as e,a0 as s}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"11代12代以及海光CPU服务器ESXi无法启动问题","description":"","frontmatter":{"title":"11代12代以及海光CPU服务器ESXi无法启动问题","date":"2022-10-20T16:09:19.000Z","category":"ESXi","tags":["ESXi"]},"headers":[],"relativePath":"posts/11代12代以及海光CPU服务器ESXi无法启动问题.md","filePath":"posts/11代12代以及海光CPU服务器ESXi无法启动问题.md","lastUpdated":1783008259000}'),E={name:"posts/11代12代以及海光CPU服务器ESXi无法启动问题.md"};function n(p,i,o,r,A,l){return a(),e("div",null,[...i[0]||(i[0]=[s('<h1 id="_0x01-背景" tabindex="-1">0x01 背景 <a class="header-anchor" href="#_0x01-背景" aria-label="Permalink to &quot;0x01 背景&quot;">​</a></h1><p>NUC9i7QNX因为有2个PCI-E槽让我眼热了很久，最近的价格很香，就在闲鱼淘了2台。</p><p>双PCI-E插槽，可以插2个PCI-E的SDR卡，可以很愉快的跑5G NSA！之前用M920X只有一个PCIE，只能插一块卡，导致只能跑5G SA。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/NUC12_%E6%B5%B7%E5%85%89CPU%E6%9C%8D%E5%8A%A1%E5%99%A8ESXi%E6%97%A0%E6%B3%95%E5%90%AF%E5%8A%A8%E9%97%AE%E9%A2%98/1669451114071.png" alt="nuc9i7qnx"></p><p>也可以装一块BCM57810卡插2根猫棒，再来个X520/X710/X540/X550的万兆网卡，加上板载2个千兆口，做软路由也一点问题都没。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/11%E4%BB%A312%E4%BB%A3%E4%BB%A5%E5%8F%8A%E6%B5%B7%E5%85%89CPU%E6%9C%8D%E5%8A%A1%E5%99%A8ESXi%E6%97%A0%E6%B3%95%E5%90%AF%E5%8A%A8%E9%97%AE%E9%A2%98/1669452595443.png" alt="nuc9软路由"> 因为NUC9是计算卡+PCIE底板的结构，就看了下最新的计算卡，然后就整了一台最新的NUC12BTMi9猛兽峡谷。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/NUC12_%E6%B5%B7%E5%85%89CPU%E6%9C%8D%E5%8A%A1%E5%99%A8ESXi%E6%97%A0%E6%B3%95%E5%90%AF%E5%8A%A8%E9%97%AE%E9%A2%98/1669451034922.png" alt="nuc12btmi9"></p><p>然后发现NUC11还有的2个PCIE插槽到了NUC12就剩1个了，让人无语，虽然可以插一块SDR100的PCIE卡，但终究不爽，不过板载的10G+2.5G口还可以。</p><h1 id="_0x02-esxi无法安装的问题" tabindex="-1">0x02 ESXi无法安装的问题 <a class="header-anchor" href="#_0x02-esxi无法安装的问题" aria-label="Permalink to &quot;0x02 ESXi无法安装的问题&quot;">​</a></h1><p>既然没法做sdr测试机，那就做ESXi服务器试试吧，毕竟12代i9的性能还是杠杠的，然后安装esxi时候就坑了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/11%E4%BB%A312%E4%BB%A3%E4%BB%A5%E5%8F%8A%E6%B5%B7%E5%85%89CPU%E6%9C%8D%E5%8A%A1%E5%99%A8ESXi%E6%97%A0%E6%B3%95%E5%90%AF%E5%8A%A8%E9%97%AE%E9%A2%98/1669451612545.png" alt="esxi紫屏"></p><p>先排除了内存问题，看报错感觉像是CPU的问题，于是打算再找几个没跑过esxi的机器上试试，果然，在i9-11900K的台式机和国产海光CPU的服务器上，也遇到了这个问题，可以初步判断是ESXi支持的CPU列表中没有这几款CPU导致的。</p><h1 id="_0x03-解决问题的方法" tabindex="-1">0x03 解决问题的方法 <a class="header-anchor" href="#_0x03-解决问题的方法" aria-label="Permalink to &quot;0x03 解决问题的方法&quot;">​</a></h1><p>在安装ESXi的时候，引导后，按<code>Shift+O</code>键。 进入命令行后，在<code>runweasel cdromBoot</code>之后输入<code>autoPartitionOSDataSize=4096</code>用于减小<code>VMFSL</code>空间，再加上<code>cpuUniformityHardCheckPanic=FALSE</code>来取消CPU的检查，之后回车继续安装。</p><p>安装完成后，如果直接重启还会遇到紫屏问题，需要重新按<code>Shift+O</code>键来输入取消检查的命令，每次启动都这样做太麻烦了。</p><p>所以安装完成后，先开启SSH，登录进去后，执行命令关闭CPU启动检查功能就可以了。</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">esxcli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> settings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kernel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cpuUniformityHardCheckPanic</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FALSE</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/11%E4%BB%A312%E4%BB%A3%E4%BB%A5%E5%8F%8A%E6%B5%B7%E5%85%89CPU%E6%9C%8D%E5%8A%A1%E5%99%A8ESXi%E6%97%A0%E6%B3%95%E5%90%AF%E5%8A%A8%E9%97%AE%E9%A2%98/1669452648059.png" alt="nuc12"> 在海光CPU的服务器同样有这个问题，虽然是AMD的EPYC换皮，但并没有用加到ESXi的支持列表中。</p><p>PS：服务器的拖拉机起飞太猛了，完全扛不住，所以做了散热改造，目前勉强能忍受 T_T</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/11%E4%BB%A312%E4%BB%A3%E4%BB%A5%E5%8F%8A%E6%B5%B7%E5%85%89CPU%E6%9C%8D%E5%8A%A1%E5%99%A8ESXi%E6%97%A0%E6%B3%95%E5%90%AF%E5%8A%A8%E9%97%AE%E9%A2%98/1669452835355.png" alt="海光CPU测试服务器"></p>',20)])])}const C=t(E,[["render",n]]);export{c as __pageData,C as default};
